  var h='<div class="card">';
  h+='<div class="hd"><div class="ic"><svg viewBox="0 0 24 24"><path d="M12 3v6"/><path d="M9 6l3-3 3 3"/><path d="M5 13l3 3 4-5 4 4 3-4"/><path d="M4 20h16"/></svg></div>';
